using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() — returns JsonTypeInfo<T> directly (no cast needed)
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"  Serialized: {json}");

// 2) TryGetTypeInfo<T>() — probe without throwing
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? resolved))
{
    Console.WriteLine($"TryGetTypeInfo<Person> → resolved: {resolved!.Type.Name}");
}

// Now try a type that won't resolve (custom resolver that knows nothing)
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new NoOpResolver()
};

if (limited.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? missing))
{
    Console.WriteLine($"TryGetTypeInfo<Person> → resolved: {missing!.Type.Name}");
}
else
{
    Console.WriteLine("TryGetTypeInfo<Person> → not available (no exception thrown)");
}

// --- Types ---

public record Person(string Name, int Age);

/// A resolver that never resolves any type.
file sealed class NoOpResolver : IJsonTypeInfoResolver
{
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) => null;
}
EOF

